// Process file
function processFile(filePath) {
  let content = fs.readFileSync(filePath, 'utf-8');
  const subject = detectSubject(filePath);
  if (!subject) { console.log(`  SKIP: ${filePath}`); return false; }
  const cm = contentMap[subject] || genericContent[subject];
  if (!cm) { console.log(`  SKIP: ${filePath}`); return false; }

  // Update createLesson helper
  if (content.includes('title, description, tasks') && !content.includes('examples?: string[]')) {
    content = content.replace(
      /(const createLesson = \(title: string, description: string, tasks: string\[\]\) => \(\{\s*\n\s*title, description, tasks\s*\n\}\)/,
      `const createLesson = (title: string, description: string, tasks: string[], examples?: string[], keyPoints?: string[]) => ({
  title, description, tasks, examples, keyPoints
})`
    );
  }

  // Find all createLesson calls and add data before the closing ])
  // Pattern: createLesson("...", `...`, [
  //   "task1",
  //   "task2",
  //   "task3",
  //   "task4"
  // ])
  // We need to find ])\n at the end of each createLesson call

  // Strategy: find each createLesson start, then find the matching closing ])
  const results = [];
  const regex = /createLesson\(/g;
  let m;
  while ((m = regex.exec(content)) !== null) {
    results.push(m.index);
  }

  if (results.length === 0) { console.log(`  NO createLesson calls found in ${filePath}`); return true; }

  // For each call, find its closing ])
  let offset = 0;
  const callData = [];
  for (const startIdx of results) {
    // Find the title (first string arg)
    let pos = startIdx + 'createLesson('.length;
    // Skip whitespace
    while (pos < content.length && (content[pos] === ' ' || content[pos] === '\n')) pos++;
    
    // Skip the title string
    let quoteChar = content[pos];
    pos++; // skip opening quote
    while (pos < content.length && content[pos] !== quoteChar) {
      if (content[pos] === '\\') pos++; // skip escape
      pos++;
    }
    pos++; // skip closing quote
    
    // Skip comma and whitespace
    while (pos < content.length && (content[pos] === ',' || content[pos] === ' ' || content[pos] === '\n')) pos++;
    
    // Skip the description string (backtick)
    quoteChar = content[pos]; // should be `
    pos++; // skip opening `
    let depth = 1;
    while (pos < content.length && depth > 0) {
      if (content[pos] === '\\') pos++; // skip escape
      if (content[pos] === quoteChar) depth--;
      pos++;
    }
    
    // Skip comma and whitespace
    while (pos < content.length && (content[pos] === ',' || content[pos] === ' ' || content[pos] === '\n')) pos++;
    
    // Now we're at the tasks array [
    pos++; // skip [
    
    // Find matching ]
    depth = 1;
    while (pos < content.length && depth > 0) {
      if (content[pos] === '[') depth++;
      if (content[pos] === ']') depth--;
      pos++;
    }
    
    // pos now points after the ]
    // Check if next chars are , or \n followed by optional examples/keyPoints
    let insertPos = pos;
    
    // Extract title from content
    let titleStart = startIdx + 'createLesson('.length;
    while (content[titleStart] !== '"' && content[titleStart] !== "'" && titleStart < pos) titleStart++;
    titleStart++;
    let titleEnd = titleStart;
    while (titleEnd < pos && content[titleEnd] !== '"' && content[titleEnd] !== "'" && content[titleEnd] !== '`') titleEnd++;
    const title = content.substring(titleStart, titleEnd);
    
    // Extract tasks
    const tasksStart = pos - 1; // pos is after ], tasks is before
    let tasksEnd = tasksStart;
    let td = 0;
    for (let p = tasksStart; p >= 0; p--) {
      if (content[p] === '[') td++;
      if (content[p] === ']') { td--; if (td === 0) { tasksEnd = p; break; } }
    }
    const tasksContent = content.substring(tasksStart, tasksEnd);
    
    const keyPoints = cm.keyPoints(title);
    const examples = cm.examples(title);
    const kpStr = keyPoints.map(k => `          "${k}"`).join(',\n');
    const exStr = examples.map(e => `          "${e}"`).join(',\n');
    
    const newData = `,\n        [\n${kpStr}\n        ],\n        [\n${exStr}\n        ])`;
    
    // Check if already has examples/keyPoints (idempotency)
    const checkStr = content.substring(insertPos, Math.min(insertPos + 50, content.length));
    if (checkStr.includes('examples') || checkStr.includes('keyPoints')) {
      console.log(`  SKIP (already has data) at position ${insertPos}`);
      continue;
    }
    
    callData.push({ insertPos, newData, title });
  }

  // Process in reverse order
  for (let i = callData.length - 1; i >= 0; i--) {
    const d = callData[i];
    content = content.substring(0, d.insertPos) + d.newData + content.substring(d.insertPos);
  }

  fs.writeFileSync(filePath, content, 'utf-8');
  console.log(`  Updated ${callData.length} lessons`);
  return true;
}

function detectSubject(filePath) {
  for (const key of Object.keys(contentMap)) {
    if (filePath.includes(key + '/')) return key;
  }
  for (const key of Object.keys(genericContent)) {
    if (filePath.includes(key + '/')) return key;
  }
  return null;
}

